(window.webpackJsonp=window.webpackJsonp||[]).push([[444],{443:function(s){s.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-comment\\">/**\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number[]}</span> <span class=\\"hljs-variable\\">A</span></span>\\n * <span class=\\"hljs-doctag\\">@return <span class=\\"hljs-type\\">{boolean}</span></span>\\n */</span>\\n<span class=\\"hljs-keyword\\">var</span> canThreePartsEqualSum = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">A</span>) </span>{\\n  <span class=\\"hljs-keyword\\">if</span>(A.length&lt;<span class=\\"hljs-number\\">3</span>)<span class=\\"hljs-keyword\\">return</span> <span class=\\"hljs-literal\\">false</span>\\n  <span class=\\"hljs-keyword\\">let</span> sum=A.reduce(<span class=\\"hljs-function\\">(<span class=\\"hljs-params\\">a,b</span>)=&gt;</span>a+b)\\n  <span class=\\"hljs-keyword\\">if</span>(sum % <span class=\\"hljs-number\\">3</span>!==<span class=\\"hljs-number\\">0</span>)<span class=\\"hljs-keyword\\">return</span> <span class=\\"hljs-literal\\">false</span>\\n  <span class=\\"hljs-keyword\\">let</span> target=sum/<span class=\\"hljs-number\\">3</span>\\n  <span class=\\"hljs-keyword\\">let</span> curSum=<span class=\\"hljs-number\\">0</span>\\n  <span class=\\"hljs-keyword\\">let</span> time=<span class=\\"hljs-number\\">0</span>\\n  <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">0</span>;i&lt;A.length;i++){\\n    curSum+=A[i]\\n    <span class=\\"hljs-keyword\\">if</span>(curSum===target){\\n      curSum=<span class=\\"hljs-number\\">0</span>\\n      time++\\n    }\\n  }\\n  <span class=\\"hljs-keyword\\">return</span> time===<span class=\\"hljs-number\\">3</span> || (time&gt;<span class=\\"hljs-number\\">3</span> &amp;&amp; target===<span class=\\"hljs-number\\">0</span>)\\n};\\n</code></pre>\\n"],"titleSlug":"partition-array-into-three-parts-with-equal-sum","hasThinking":false,"content":"<p>\u7ed9\u4f60\u4e00\u4e2a\u6574\u6570\u6570\u7ec4 <code>arr</code>\uff0c\u53ea\u6709\u53ef\u4ee5\u5c06\u5176\u5212\u5206\u4e3a\u4e09\u4e2a\u548c\u76f8\u7b49\u7684 <strong>\u975e\u7a7a</strong> \u90e8\u5206\u65f6\u624d\u8fd4\u56de\xa0<code>true</code>\uff0c\u5426\u5219\u8fd4\u56de <code>false</code>\u3002</p>\\n\\n<p>\u5f62\u5f0f\u4e0a\uff0c\u5982\u679c\u53ef\u4ee5\u627e\u51fa\u7d22\u5f15\xa0<code>i + 1 < j</code>\xa0\u4e14\u6ee1\u8db3\xa0<code>(arr[0] + arr[1] + ... + arr[i] == arr[i + 1] + arr[i + 2] + ... + arr[j - 1] == arr[j] + arr[j + 1] + ... + arr[arr.length - 1])</code>\xa0\u5c31\u53ef\u4ee5\u5c06\u6570\u7ec4\u4e09\u7b49\u5206\u3002</p>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u793a\u4f8b 1\uff1a</strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>arr = [0,2,1,-6,6,-7,9,1,2,0,1]\\n<strong>\u8f93\u51fa\uff1a</strong>true\\n<strong>\u89e3\u91ca\uff1a</strong>0 + 2 + 1 = -6 + 6 - 7 + 9 + 1 = 2 + 0 + 1\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 2\uff1a</strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>arr = [0,2,1,-6,6,7,9,-1,2,0,1]\\n<strong>\u8f93\u51fa\uff1a</strong>false\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 3\uff1a</strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>arr = [3,3,6,5,-2,2,5,1,-9,4]\\n<strong>\u8f93\u51fa\uff1a</strong>true\\n<strong>\u89e3\u91ca\uff1a</strong>3 + 3 = 6 = 5 - 2 + 2 + 5 + 1 - 9 + 4\\n</pre>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u63d0\u793a\uff1a</strong></p>\\n\\n<ul>\\n\\t<li><code>3 <= arr.length <= 5 * 10<sup>4</sup></code></li>\\n\\t<li><code>-10<sup>4</sup> <= arr[i] <= 10<sup>4</sup></code></li>\\n</ul>\\n","title":"1013. \u5c06\u6570\u7ec4\u5206\u6210\u548c\u76f8\u7b49\u7684\u4e09\u4e2a\u90e8\u5206","relatedTags":["\u6570\u7ec4"],"difficult":"Easy","lang":["javascript"],"uniqueID":"1013"}')}}]);